const { Pool } = require\(''pg''\);
const pool = new Pool\({ connectionString: process.env.DATABASE_URL, ssl: { rejectUnauthorized: false } }\);

\(async \(\) => {
  await pool.query\(''SET search_path TO zensai''\);

  // users 컬럼 확인
  const cols = await pool.query\(\\`SELECT column_name FROM information_schema.columns WHERE table_schema=''zensai'' AND table_name=''users'' ORDER BY ordinal_position\\`\);
  console.log\(''users 컬럼:'', cols.rows.map\(r => r.column_name\).join\('', ''\)\);

  // 사용자 목록
  const users = await pool.query\(\\`SELECT user_id, login_id, name, role, partner_code FROM users ORDER BY user_id\\`\);
  console.log\(''\\n=== 사용자 목록 ===''\);
  console.table\(users.rows\);

  // 구매내역
  const purchases = await pool.query\(''SELECT COUNT\(*\) as total FROM customer_purchases''\);
  console.log\(''\\n구매내역:'', purchases.rows[0].total, ''건''\);

  // 포인트
  const points = await pool.query\(''SELECT COUNT\(*\) as total FROM customer_points WHERE available_points > 0''\);
  console.log\(''포인트 보유 고객:'', points.rows[0].total, ''명''\);

  // 태그
  const tags = await pool.query\(''SELECT COUNT\(*\) as total FROM customer_tags''\);
  console.log\(''고객 태그:'', tags.rows[0].total, ''개''\);

  // 세그먼트
  const segments = await pool.query\(''SELECT COUNT\(*\) as total FROM customer_segments''\);
  console.log\(''세그먼트:'', segments.rows[0].total, ''개''\);

  await pool.end\(\);
}\)\(\).catch\(e => { console.error\(e.message\); process.exit\(1\); }\);
")
